features.snippet:
module clockgate(output out_clk, input in_clk, en);
wire en_reg;
assign out_clk = in_clk & en_reg;
always @(posedge in_clk) en_reg <= #1 en;
endmodule

module test(output results, input dclk, test_sig);
reg results;
always @(posedge dclk) results <= test_sig ? 1'b1 : 1'b0;
endmodule
